(* TZPID ID1802 Opera Omnia source model *)
ClearAll[K1802, Cr1802, T, R, A, W, I, N];
eq1802$1 = HoldForm[\oint_C \frac{dz}{z - p_0} = 2\pi i \cdot \nu];
eq1802$2 = HoldForm[V[\Phi] = \|\Phi - \Phi_\text{target}\|^2, \quad \frac{dV}{dt} < 0];
eq1802$3 = HoldForm[\text{StellarFlow}(t) = \text{Weierstrass}\!\left[\text{coords modulated by } J_0(\omega_\text{cymatic}\,t),\,\arcsin(\sin(\omega_\text{precession}\,t)),\,(1+\epsilon\sin(n\omega_\text{rotation}\,t))\right]];
eq1802$4 = HoldForm[\alpha \to 2\pi J_0(\omega_\text{cymatic}\,t)];
eq1802$5 = HoldForm[\hat{H}_\text{Trawin}];
K1802 = HoldForm[{eq1802$1, eq1802$2, eq1802$3, eq1802$4, eq1802$5}];
Cr1802[expr_] := HoldForm[N[I[W[A[R[T[expr]]]]]]];
Result1802 = Cr1802[K1802];
